const input = $input.first().json;
const body = input.body ?? input;
const raw = String(input.chatInput || body.userQuery || "").trim();
let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch {
  parsed = { userQuery: raw };
}
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
const chatId    = String(parsed.chatId    || body.chatId    || input.sessionId || "").trim() || uuidv4();
const email = String(parsed.email || body.email || "");
const userQuery = String(parsed.userQuery || body.userQuery || raw);
const timestamp = String(parsed.timestamp || body.timestamp || new Date().toISOString());
const agentInput = `[CitizenConnect Request]
Email: ${email}
Chat ID: ${chatId}
Timestamp: ${timestamp}
User Query: ${userQuery}
Classify the above query and call the appropriate tool with this EXACT input payload:
{
  "email": "${email}",
  "chatId": "${chatId}",
  "chatName": "<your generated chatName>",
  "userQuery": "${userQuery}",
  "userLanguage": "<detected language>",
  "translatedQuery": "<English translation>",
  "context": "<classified context>",
  "intent": "<classified intent>",
  "confidence": <0..1>,
  "recalledAnswer": "",
  "conversationHistory": "",
  "timestamp": "${timestamp}"
}`;
return [{
  json: {
    agentInput,
    email,
    chatId,
    userQuery,
    timestamp
  }
}];

const agentOutput = $input.first().json;
const ctx = $('Code in JavaScript').first().json;

function safeJsonParse(x) {
  if (x == null) return null;
  if (typeof x === "object") return x;
  const s = String(x).trim();
  if (!s) return null;
  try { return JSON.parse(s); } catch {}
  const firstObj = s.indexOf("{");
  const lastObj  = s.lastIndexOf("}");
  const firstArr = s.indexOf("[");
  const lastArr  = s.lastIndexOf("]");
  if (firstObj !== -1 && lastObj !== -1 && lastObj > firstObj) {
    try { return JSON.parse(s.slice(firstObj, lastObj + 1)); } catch {}
  }
  if (firstArr !== -1 && lastArr !== -1 && lastArr > firstArr) {
    try { return JSON.parse(s.slice(firstArr, lastArr + 1)); } catch {}
  }
  return null;
}

const outerRaw =
  agentOutput.output ??
  agentOutput.text ??
  agentOutput.response ??
  agentOutput.message ??
  agentOutput ??
  "";

const outer = safeJsonParse(outerRaw) ?? {};

// ── Log if parse failed (helps debug) ──────────────────────────
if (!outer || Object.keys(outer).length === 0) {
  console.error('[Parse Agent Output] Failed to parse agent response:', 
    JSON.stringify(outerRaw).slice(0, 300));
}

let payload = outer;

if (!payload?.answerText) {
  if (outer.input && !outer.answerText) {
    const fromInput = safeJsonParse(outer.input);
    if (fromInput && typeof fromInput === "object") {
      payload = { ...fromInput, answerText: null };
    }
  }
  if (!payload?.answerText) {
    let toolWrapper = outer;
    if (toolWrapper && typeof toolWrapper === "object") {
      const toolKey = Object.keys(toolWrapper).find(k =>
        String(k).toLowerCase().includes("balance_lookup")
      );
      if (toolKey) toolWrapper = toolWrapper[toolKey];
    }
    const toolResult =
      toolWrapper?.result ??
      outer?.["Tool_-_Balance_Lookup_response"]?.result ??
      outer?.["Tool_-_Balance_Lookup_Response"]?.result ??
      outer?.["Tool_Balance_Lookup_response"]?.result ??
      null;
    const parsedResult = safeJsonParse(toolResult);
    if (Array.isArray(parsedResult)) payload = parsedResult[0] ?? {};
    else if (parsedResult && typeof parsedResult === "object") payload = parsedResult;
  }
}

const answerText =
  payload.answerText ??
  payload.answer ??
  payload.translatedRatepayerResponse ??
  payload.resultText ??
  "I was unable to retrieve your account details. Please try again.";

let confidenceScore = Number(payload.confidenceScore ?? payload.confidence ?? 0);
if (!Number.isFinite(confidenceScore)) confidenceScore = 0;
confidenceScore = Math.max(0, Math.min(1, confidenceScore));

let suggestedQueries = Array.isArray(payload.suggestedQueries)
  ? payload.suggestedQueries.map(s => String(s ?? ""))
  : [];
if (suggestedQueries.length < 2) {
  suggestedQueries = ["Check my balance", "Set up a payment plan", "Speak to an agent"];
}

const nowIso        = new Date().toISOString();
const queryTimestamp = String(ctx.timestamp ?? nowIso);
const isEscalated   = Boolean(payload.is_escalated_status ?? payload.escalationFlag ?? false);

return [{
  json: {
    // ── Identity ───────────────────────────────────────────────
    email:                ctx.email          ?? payload.email ?? "",
    chatId:               ctx.chatId         ?? payload.chatId ?? "",
    chatName:             String(payload.chatName ?? "New Chat"),

    // ── Query ──────────────────────────────────────────────────
    userQuery:            String(ctx.userQuery ?? ""),
    translatedQuery:      String(payload.translatedQuery ?? ctx.userQuery ?? ""),
    queryLanguage:        String(payload.nativeLanguageName ?? payload.userLanguage ?? "Unknown"),
    queryTimestamp,

    // ── Answer ─────────────────────────────────────────────────
    answerText:           String(answerText),
    translatedAnswer:     String(payload.translatedRatepayerResponse ?? answerText),
    nativeLanguageName:   String(payload.nativeLanguageName ?? payload.userLanguage ?? "Unknown"),
    confidenceScore,
    responseTimestamp:    nowIso,
    suggestedQueries,

    // ── Classification ─────────────────────────────────────────
    context:              String(payload.context  ?? "other"),
    intent:               String(payload.intent   ?? "unclear"),

    // ── Storage decision (agent-decided) ───────────────────────
    shouldStore:          Boolean(payload.shouldStore  ?? false),
    storeReason:          String(payload.storeReason   ?? ""),

    // ── Escalation ─────────────────────────────────────────────
    isEscalated,
    escalationTimestamp:  isEscalated ? nowIso : null,
  }
}];

const res = $('Parse Agent Output').first().json;

return [{
  json: {
    status:          "success",
    email:           String(res.email          ?? ""),
    chatId:          String(res.chatId         ?? ""),
    chatName:        String(res.chatName        ?? "New Chat"),
    answerText:      String(res.translatedAnswer ?? res.answerText ?? ""),
    confidenceScore: Number.isFinite(Number(res.confidenceScore)) 
                       ? Number(res.confidenceScore) : 0,
    suggestedQueries: Array.isArray(res.suggestedQueries) 
                       ? res.suggestedQueries : ["", ""],
  }
}];

const r = $('Parse Agent Output').first().json;

if (!r.shouldStore) {
  return [];
}

return [{
  json: {
    text: `Q: ${r.userQuery}\nA: ${r.answerText}`,
    metadata: {
      email:     r.email     || 'no-email',
      chatId:    r.chatId    || '',
      intent:    r.intent    || '',
      context:   r.context   || '',
      timestamp: r.responseTimestamp || new Date().toISOString()
    }
  }
}];
